&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;जीते जी इलाहाबाद&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;साहित्य अकादमी ने 2025 के अपने वार्षिक पुरस्कारों की घोषणा की, जिसमें 24 भारतीय भाषाओं में साहित्यिक उत्कृष्टता को मान्यता दी गई।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;हिंदी प्राप्तकर्ता:&lt;/strong&gt; प्रसिद्ध लेखिका &lt;strong&gt;ममता कालिया&lt;/strong&gt; ने अपनी आत्मकथा &lt;strong&gt;&amp;#39;जीते जी इलाहाबाद&amp;#39;&lt;/strong&gt; के लिए पुरस्कार जीता।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;शैली:&lt;/strong&gt; यह पुस्तक &lt;strong&gt;संस्मरण&lt;/strong&gt; श्रेणी के अंतर्गत आती है, जो उनके अनुभवों और इलाहाबाद (प्रयागराज) के साहित्यिक परिवेश को दर्शाती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अन्य भाषा विजेता:&lt;/strong&gt; &lt;strong&gt;नवतेज सरना&lt;/strong&gt; ने अंग्रेजी (क्रिमसन स्प्रिंग - उपन्यास) के लिए और &lt;strong&gt;राजू बाविस्कर&lt;/strong&gt; ने मराठी (कल्याणील्या रेश - आत्मकथा) के लिए पुरस्कार जीता।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पुरस्कार राशि:&lt;/strong&gt; इस सम्मान में एक उत्कीर्ण तांबे की पट्टिका, एक शॉल और &lt;strong&gt;1,00,000 रुपये&lt;/strong&gt; का नकद पुरस्कार शामिल है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;समारोह:&lt;/strong&gt; आधिकारिक पुरस्कार प्रस्तुति &lt;strong&gt;31 मार्च, 2026&lt;/strong&gt; को निर्धारित है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;साहित्य अकादमी&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;यह भारत सरकार के संस्कृति मंत्रालय के तहत एक स्वायत्त संगठन है, जो भारतीय भाषाओं में साहित्य के प्रचार के लिए समर्पित है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;भाषा पात्रता&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;संविधान में उल्लिखित 22 भाषाओं के अलावा, अकादमी अपने वार्षिक पुरस्कारों के लिए &lt;strong&gt;अंग्रेजी&lt;/strong&gt; और &lt;strong&gt;राजस्थानी&lt;/strong&gt; को भी मान्यता देती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

