&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;आईसीसी चैंपियंस ट्रॉफी&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;2017 की जीत 21वीं सदी में पाकिस्तान की सबसे महत्वपूर्ण क्रिकेट उपलब्धियों में से एक है, क्योंकि उन्होंने टूर्नामेंट में सबसे कम रैंकिंग वाली टीम के रूप में प्रवेश किया और चैंपियन बनकर उभरे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
